import xml.etree.ElementTree as ET
from collections import deque
import json

def get_player_pos(root):
    for row in root.findall(".//Row"):
        y = int(row.get('id'))
        for tile in row.findall("Tile"):
            if tile.find("Player") is not None:
                return int(tile.get('id')), y
    return None

def bfs(start, target, walkable_types, width, height, tiles):
    queue = deque([(start, [])])
    visited = {start}

    while queue:
        (curr_x, curr_y), path = queue.popleft()

        if (curr_x, curr_y) == target:
            return path

        for dx, dy, move in [(0, -1, 'Up'), (0, 1, 'Down'), (-1, 0, 'Left'), (1, 0, 'Right')]:
            nx, ny = curr_x + dx, curr_y + dy

            if 0 <= nx < width and 0 <= ny < height:
                tile_type = tiles.get((nx, ny), "unseen")
                if (nx, ny) not in visited and tile_type in walkable_types:
                    visited.add((nx, ny))
                    new_path = path + [move]
                    queue.append(((nx, ny), new_path))
    return None

try:
    root = ET.fromstring(map_xml_string)
    width = int(root.get('width'))
    height = int(root.get('height'))

    tiles = {}
    for row in root.findall("Row"):
        y = int(row.get('id'))
        for tile in row.findall("Tile"):
            x = int(tile.get('id'))
            t_type = tile.get('type')
            tiles[(x, y)] = t_type

    start_pos = get_player_pos(root)
    if not start_pos:
        print(json.dumps([]))
    else:
        # Access inputs from input_data dictionary
        target_x = input_data['target_x']
        target_y = input_data['target_y']
        walkable = set(input_data['walkable_types'])

        # Ensure target is walkable, if not, find nearest walkable
        if tiles.get((target_x, target_y)) not in walkable:
             # Simple nearest search (spiral)
             found = False
             for r in range(1, 5):
                 for dx in range(-r, r+1):
                     for dy in range(-r, r+1):
                         if abs(dx)+abs(dy) == r: # Manhatten distance layers
                             nx, ny = target_x + dx, target_y + dy
                             if tiles.get((nx, ny)) in walkable:
                                 target_x, target_y = nx, ny
                                 found = True
                                 break
                     if found: break
                 if found: break

        path = bfs(start_pos, (target_x, target_y), walkable, width, height, tiles)

        if path:
            print(json.dumps(path))
        else:
            print(json.dumps([]))

except Exception as e:
    # Fallback empty list on error
    # print(f"Debug: {e}") # Uncomment for debugging
    print(json.dumps([]))

