import xml.etree.ElementTree as ET
import json

def get_tracked_objects(xml_string):
    root = ET.fromstring(xml_string)
    objects = []

    for row in root.findall("Row"):
        y = int(row.get("id"))
        for tile in row.findall("Tile"):
            x = int(tile.get("id"))
            for marker in tile.findall("Marker"):
                obj_id = marker.get("object_id")
                if obj_id:
                    objects.append({
                        "label": marker.text,
                        "x": x,
                        "y": y,
                        "object_id": obj_id,
                        "emoji": marker.get("emoji")
                    })
    return objects

try:
    # map_xml_string is injected automatically
    results = get_tracked_objects(map_xml_string)
    print(json.dumps(results))
except Exception as e:
    print(json.dumps({"error": str(e)}))
